const generateMockProducts = (count: number): Product[] => {
  const categories = ['Thời trang nữ', 'Thời trang nam', 'Điện tử', 'Nhà cửa & Đời sống', 'Mẹ & Bé', 'Mỹ phẩm', 'Phụ kiện'];
  const statuses: ('active' | 'draft' | 'out_of_stock')[] = ['active', 'active', 'active', 'draft', 'out_of_stock'];
  const platformsList = [
    [Platform.SHOPEE], 
    [Platform.LAZADA, Platform.FACEBOOK], 
    [Platform.TIKTOK], 
    [Platform.WOOCOMMERCE, Platform.SHOPEE],
    [Platform.FACEBOOK]
  ];

  return Array.from({ length: count }).map((_, i) => {
    const id = i + 100; // Start IDs from 100 to avoid conflict with static items
    const price = Math.floor(Math.random() * 2000000) + 50000;
    const hasSale = Math.random() > 0.7;
    const stock = Math.floor(Math.random() * 200);
    const category = categories[Math.floor(Math.random() * categories.length)];
    // Use loremflickr for more product-like images based on category keywords
    const keyword = category.split(' ')[0] === 'Thời' ? 'fashion' : category.split(' ')[0] === 'Điện' ? 'tech' : 'product';

    return {
      id: `P${id}`,
      name: `Sản phẩm Demo ${id} - ${category}`,
      sku: `SKU-${id}-${Math.floor(Math.random() * 1000)}`,
      price: price,
      salePrice: hasSale ? price * 0.8 : undefined,
      importPrice: Math.floor(price * 0.6), // Import price approx 60% of retail
      currency: 'VND',
      stock: stock,
      minStock: 10,
      maxStock: 500,
      warehouseStocks: distributeStock(stock),
      totalSold: Math.floor(Math.random() * 500),
      platforms: platformsList[Math.floor(Math.random() * platformsList.length)],
      image: `https://loremflickr.com/200/200/${keyword}?random=${id}`,
