export const MOCK_REALTIME_SALES: HourlySalesData[] = Array.from({ length: 24 }).map((_, i) => {
  const hour = i.toString().padStart(2, '0') + ':00';
  const base = i >= 8 && i <= 22 ? 20000000 : 2000000;
  const randomFactorToday = Math.random() * 0.5 + 0.8;
  const randomFactorYest = Math.random() * 0.5 + 0.8;
  return { hour, today: i <= new Date().getHours() ? Math.floor(base * randomFactorToday) : 0, yesterday: Math.floor(base * randomFactorYest) };
});

