export const MOCK_TOP_SKUS: TopSKU[] = Array.from({ length: 20 }).map((_, i) => {
  const products = [...FULL_STATIC_PRODUCTS, ...generateMockProducts(20)];
  const product = products[i % products.length];

  return {
    rank: i + 1,
    id: product.id,
    name: product.name,
    image: product.image,
    orders: Math.floor(Math.random() * 50) + (20 - i) * 2, // Descending orderish
    revenue: (Math.floor(Math.random() * 50) + (20 - i) * 2) * product.price,
    stock: product.stock,
    views: Math.floor(Math.random() * 5000) + 1000
  };
}).sort((a, b) => b.revenue - a.revenue).map((item, idx) => ({ ...item, rank: idx + 1 }));

