const generateMockOrders = (count: number): Order[] => {
  // ... (Same content as previous file)
  const platforms = [Platform.SHOPEE, Platform.LAZADA, Platform.TIKTOK, Platform.FACEBOOK, Platform.WOOCOMMERCE];

  const shopIds: Record<Platform, string[]> = {
    [Platform.SHOPEE]: ['sh1', 'sh2', 'sh3', 'sh4', 'sh5'],
    [Platform.LAZADA]: ['lz1', 'lz2', 'lz3', 'lz4'],
    [Platform.TIKTOK]: ['tt1', 'tt2', 'tt3'],
    [Platform.FACEBOOK]: ['fb1', 'fb2', 'fb3'],
    [Platform.WOOCOMMERCE]: ['woo1']
  };

  const statuses: Order['status'][] = ['pending', 'processing', 'shipping', 'delivered', 'cancelled', 'returned'];
  const carriers = ['SPX Express', 'J&T Express', 'Giao Hàng Nhanh', 'Viettel Post', 'Ninja Van'];
  const shippingMethods = ['Nhanh', 'Hỏa tốc', 'Tiết kiệm', 'Thường'];
  const firstNames = ['An', 'Bình', 'Chi', 'Dũng', 'Giang', 'Hương', 'Khánh', 'Lan', 'Minh', 'Nam', 'Oanh', 'Phúc', 'Quân', 'Thảo', 'Uyên', 'Vinh', 'Yến'];
  const lastNames = ['Nguyễn', 'Trần', 'Lê', 'Phạm', 'Hoàng', 'Huỳnh', 'Phan', 'Vũ', 'Võ', 'Đặng', 'Bùi', 'Đỗ', 'Hồ', 'Ngô', 'Dương', 'Lý'];
  const notes = ['Giao giờ hành chính', 'Gọi trước khi giao', 'Nhà có chó dữ', 'Để hàng ở cổng nếu không có nhà', 'Gói hàng cẩn thận giúp mình', 'Che tên sản phẩm nhé'];

  return Array.from({ length: count }).map((_, i) => {
    const id = 1000 + i;
    const platform = platforms[Math.floor(Math.random() * platforms.length)];
    const platformShopIds = shopIds[platform];
    const shopId = platformShopIds[Math.floor(Math.random() * platformShopIds.length)];

    const statusRand = Math.random();
    let status: Order['status'] = 'processing';
    if (statusRand < 0.1) status = 'pending';      
    else if (statusRand < 0.3) status = 'processing'; 
    else if (statusRand < 0.6) status = 'shipping';   
    else if (statusRand < 0.9) status = 'delivered';  
    else if (statusRand < 0.95) status = 'cancelled'; 
    else status = 'returned';                         

    let subStatus: Order['subStatus'] = undefined;
    if (status === 'processing') {
      const subRand = Math.random();
      if (subRand < 0.3) subStatus = 'unprocessed';
      else if (subRand < 0.7) subStatus = 'printed';
      else subStatus = 'packed';
    }

    const itemCount = Math.floor(Math.random() * 3) + 1;
    const items: OrderItem[] = Array.from({ length: itemCount }).map((__, j) => ({
      productId: `P-${id}-${j}`,
      name: `Sản phẩm ${['Áo', 'Quần', 'Túi', 'Giày', 'Mũ', 'Kính'][Math.floor(Math.random() * 6)]} Demo ${id}-${j}`,
      image: `https://loremflickr.com/200/200/fashion,product?random=${id * 10 + j}`, // Use product images
      sku: `SKU-${id}-${j}`,
      variant: ['Màu Đỏ', 'Màu Xanh', 'Size L', 'Size M', 'Full Box'][Math.floor(Math.random() * 5)],
      quantity: Math.floor(Math.random() * 2) + 1,
      price: Math.floor(Math.random() * 500000) + 50000
    }));

    const shippingFee = Math.random() > 0.7 ? 0 : (Math.random() > 0.5 ? 16500 : 32000);
    const subtotal = items.reduce((acc, item) => acc + item.price * item.quantity, 0);
    const total = subtotal + shippingFee;

    // Financial calculations
    const platformFee = Math.floor(total * 0.06); // Approx 6%
    const tax = Math.floor(total * 0.015); // 1.5% Tax
    const importCost = Math.floor(total * 0.65); // COGS approx 65%
    const profit = total - shippingFee - platformFee - tax - importCost;

    const shippingMethod = Math.random() > 0.8 ? 'Hỏa tốc' : shippingMethods[Math.floor(Math.random() * (shippingMethods.length - 1))];

    const randomDate = new Date();
    const daysAgo = Math.random() > 0.9 ? 3 : Math.floor(Math.random() * 2);
    randomDate.setDate(randomDate.getDate() - daysAgo);
    randomDate.setHours(Math.floor(Math.random() * 12) + 8);
    randomDate.setMinutes(Math.floor(Math.random() * 60));

    const timeStr = `${randomDate.getHours().toString().padStart(2, '0')}:${randomDate.getMinutes().toString().padStart(2, '0')} ${randomDate.getDate().toString().padStart(2, '0')}/${(randomDate.getMonth() + 1).toString().padStart(2, '0')}/${randomDate.getFullYear().toString().slice(-2)}`;

    const shipBy = new Date(randomDate);
    shipBy.setDate(shipBy.getDate() + 2);
    if (shippingMethod === 'Hỏa tốc') {
       shipBy.setDate(randomDate.getDate());
       shipBy.setHours(randomDate.getHours() + 4);
    }
    const shipByStr = `${shipBy.getHours().toString().padStart(2, '0')}:${shipBy.getMinutes().toString().padStart(2, '0')} ${shipBy.getDate().toString().padStart(2, '0')}/${(shipBy.getMonth() + 1).toString().padStart(2, '0')}/${shipBy.getFullYear().toString().slice(-2)}`;

    let carrier: string | undefined = carriers[Math.floor(Math.random() * carriers.length)];
    let trackingCode: string | undefined = `VN${Math.floor(Math.random() * 100000000)}`;

    if (status === 'pending') {
      carrier = undefined;
      trackingCode = undefined;
    } else if (status === 'cancelled') {
      if (Math.random() > 0.5) {
        carrier = undefined;
        trackingCode = undefined;
      }
    } else if (status === 'processing' && subStatus === 'unprocessed') {
      trackingCode = undefined;
    }

    return {
      id: `${platform === Platform.SHOPEE ? '25' : 'ORD'}${Math.floor(Math.random() * 1000000000)}`,
      customerName: `${lastNames[Math.floor(Math.random() * lastNames.length)]} ${firstNames[Math.floor(Math.random() * firstNames.length)]}`,
      platform,
      shopId,
      date: timeStr,
      shipByDate: shipByStr,
      total,
      shippingFee,
      platformFee,
      tax,
      profit,
      status,
      subStatus,
      items,
      shippingCarrier: carrier,
      shippingMethod: shippingMethod,
      isCOD: Math.random() > 0.3,
      trackingCode: trackingCode,
      note: Math.random() > 0.6 ? notes[Math.floor(Math.random() * notes.length)] : undefined // Increased chance for note
    };
  });
};

const generateManualOrders = (count: number): Order[] => {
  // ... (Same content as previous file)
  const firstNames = ['Tâm', 'Hùng', 'Vân', 'Thúy', 'Quyên', 'Long', 'Sơn', 'Tùng', 'My', 'Hạnh'];
  const lastNames = ['Đặng', 'Bùi', 'Đỗ', 'Hồ', 'Ngô', 'Dương', 'Lý', 'Vương', 'Đinh', 'Trịnh'];
  const addresses = ['Hà Nội', 'TP.HCM', 'Đà Nẵng', 'Hải Phòng', 'Cần Thơ', 'Bình Dương', 'Đồng Nai'];
  const notes = ['Giao giờ hành chính', 'Gọi trước khi giao', 'Khách quen', 'Cho xem hàng'];
  const carriers = ['Giao Hàng Tiết Kiệm', 'Giao Hàng Nhanh', 'Viettel Post', 'Ahamove', 'GrabExpress', 'Giao hàng thủ công'];

  return Array.from({ length: count }).map((_, i) => {
    const id = 5000 + i;
    // Weighted status distribution for Manual Orders
    const statusRand = Math.random();
    let status: Order['status'] = 'pending';
    let subStatus: Order['subStatus'] = undefined;

    if (statusRand < 0.15) status = 'pending';
    else if (statusRand < 0.35) {
        status = 'processing';
        subStatus = Math.random() > 0.5 ? 'unprocessed' : 'packed';
    }
    else if (statusRand < 0.65) status = 'shipping';
    else if (statusRand < 0.90) status = 'delivered';
    else if (statusRand < 0.95) status = 'cancelled';
    else status = 'returned';

    const itemCount = Math.floor(Math.random() * 2) + 1;
    const items: OrderItem[] = Array.from({ length: itemCount }).map((__, j) => ({
      productId: `M-P-${id}-${j}`,
      name: `Sản phẩm Ngoài Sàn ${id}-${j}`,
      image: `https://loremflickr.com/200/200/gift?random=${id * 10 + j}`,
      sku: `EXT-${id}-${j}`,
      variant: 'Tiêu chuẩn',
      quantity: Math.floor(Math.random() * 3) + 1,
      price: Math.floor(Math.random() * 300000) + 100000
    }));

    const subtotal = items.reduce((acc, item) => acc + item.price * item.quantity, 0);
    const shippingFee = Math.random() > 0.5 ? 30000 : 0;
    const total = subtotal + shippingFee;

    // For manual orders, platform fee is 0, but maybe shipping cost is paid by shop?
    const platformFee = 0; 
    const tax = 0; // Often no tax calculated for small manual
    const importCost = Math.floor(total * 0.6);
    const profit = total - shippingFee - importCost;

    const randomDate = new Date();
    randomDate.setDate(randomDate.getDate() - Math.floor(Math.random() * 5));
    const timeStr = `${randomDate.getHours().toString().padStart(2, '0')}:${randomDate.getMinutes().toString().padStart(2, '0')} ${randomDate.getDate().toString().padStart(2, '0')}/${(randomDate.getMonth() + 1).toString().padStart(2, '0')}/${randomDate.getFullYear().toString().slice(-2)}`;

    let carrier = undefined;
    if (status !== 'pending' && status !== 'cancelled') {
        carrier = carriers[Math.floor(Math.random() * carriers.length)];
    }

    const customerName = `${lastNames[Math.floor(Math.random() * lastNames.length)]} ${firstNames[Math.floor(Math.random() * firstNames.length)]}`;

    return {
      id: `EXT-${Date.now().toString().slice(-4)}${i.toString().padStart(3, '0')}`,
      customerName,
      customerPhone: `09${Math.floor(Math.random() * 100000000)}`,
      address: `${Math.floor(Math.random() * 100)} Đường số ${Math.floor(Math.random() * 10)}, ${addresses[Math.floor(Math.random() * addresses.length)]}`,
      platform: 'Manual',
      shopId: 'fb1', // Assign to a default shop or make generic
      date: timeStr,
      shipByDate: timeStr, // simplified
      total,
      shippingFee,
      platformFee,
      tax,
      profit,
      status,
      subStatus,
      items,
      shippingCarrier: carrier,
      shippingMethod: 'Tiêu chuẩn',
      isCOD: true,
      note: Math.random() > 0.7 ? notes[Math.floor(Math.random() * notes.length)] : undefined
    };
  });
};

