    salePrice: 0,
    importPrice: 0,
    currency: 'VND',
    stock: 0,
    warehouseStocks: {},
    totalSold: 0,
    platforms: [],
    image: '',
    gallery: [],
    video: '',
    description: '',
    category: '',
