      } else if (vals2.length > 0) {
          // Only group 2 (unlikely but possible)
          vals2.forEach(v2 => {
              const name = v2;
              const existing = formData.variants?.find(v => v.name === name);
              newVariants.push(existing || {
                  id: `v-${Date.now()}-${Math.random()}`,
