  };

  // Helper to extract context for warning
  const getWarningContext = (keyword: string, text: string) => {
      const index = text.toLowerCase().indexOf(keyword.toLowerCase());
      if (index === -1) return keyword;

      const start = Math.max(0, index - 20);
      const end = Math.min(text.length, index + keyword.length + 20);

      let snippet = text.substring(start, end);
      if (start > 0) snippet = '...' + snippet;
      if (end < text.length) snippet = snippet + '...';

      // Highlight the keyword simply by wrapping (React needs parsing or dangerouslySetInnerHtml, but for simplicity here we just return text)
      return snippet;
  };

